import{c as s,a0 as i,U as r,j as o,g as e,n as l,o as c,m as d}from"./chunks/framework.Dvkoa_vi.js";const b=JSON.parse('{"title":"Curso Normalización","description":"Portada del curso de normalización de aplicaciones — 25 sesiones de 1 h 30 min organizadas en seis bloques.","frontmatter":{"title":"Curso Normalización","description":"Portada del curso de normalización de aplicaciones — 25 sesiones de 1 h 30 min organizadas en seis bloques.","outline":[2,2]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),t={name:"index.md"};function p(u,a,g,_,m,h){const n=i("CopyOrDownloadAsMarkdownButtons");return r(),o("div",null,[a[0]||(a[0]=e("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? View /curso-normalizacion/llms.txt for optimized Markdown documentation, or /curso-normalizacion/llms-full.txt for full documentation bundle",-1)),a[1]||(a[1]=e("h1",{id:"curso-normalizacion",tabindex:"-1"},[l("Curso Normalización "),e("a",{class:"header-anchor",href:"#curso-normalizacion","aria-label":"Permalink to “Curso Normalización”"},"​")],-1)),c(n),a[2]||(a[2]=d('<p>Material del curso para trabajar Oracle, .NET y Vue dentro del flujo habitual de desarrollo de la Universidad de Alicante.</p><p><strong>25 sesiones de 1 h 30 min</strong> organizadas en seis bloques. Consulta la <a href="./organizacion-del-curso.html">organización del curso</a> para ver el calendario completo y el reparto de sesiones.</p><h2 id="preparacion" tabindex="-1">Preparación <a class="header-anchor" href="#preparacion" aria-label="Permalink to “Preparación”">​</a></h2><a class="landing-card" href="./00-preparacion/"><span class="landing-card__eyebrow">Bloque 0</span><strong class="landing-card__title">Configuración del entorno</strong><span class="landing-card__description">Instalación y configuración previa: Git, SSH, npm, NuGet, .NET SDK, Visual Studio y VS Code para conectarse al Azure DevOps de la UA. No cuenta en la numeración de sesiones.</span><span class="landing-card__link">Ir a la preparación →</span></a><h2 id="oracle-—-sesiones-1-a-2" tabindex="-1">Oracle — Sesiones 1 a 2 <a class="header-anchor" href="#oracle-—-sesiones-1-a-2" aria-label="Permalink to “Oracle — Sesiones 1 a 2”">​</a></h2><a class="landing-card" href="./01-oracle/"><span class="landing-card__eyebrow">Bloque 1 · 2 sesiones</span><strong class="landing-card__title">Oracle</strong><span class="landing-card__description">Fundamentos ADM/WEB, tablas y vistas, paquetes CRUD y tres ejercicios entregables: catálogo simple, diseño de vistas y procedimientos en paquetes con detección de solapamiento.</span><span class="landing-card__link">Ir al índice Oracle →</span></a><h2 id="net-—-sesiones-3-a-5" tabindex="-1">.NET — Sesiones 3 a 5 <a class="header-anchor" href="#net-—-sesiones-3-a-5" aria-label="Permalink to “.NET — Sesiones 3 a 5”">​</a></h2><a class="landing-card" href="./02-dotnet/"><span class="landing-card__eyebrow">Bloque 2 · 3 sesiones</span><strong class="landing-card__title">.NET Core 10</strong><span class="landing-card__description">APIs REST normalizadas con .NET Core 10, DTOs, controladores, servicios e integración con Oracle. Validación, errores y DataTable se ven en Integración.</span><span class="landing-card__link">Ir al índice .NET →</span></a><h2 id="vue-—-sesiones-6-a-10" tabindex="-1">Vue — Sesiones 6 a 10 <a class="header-anchor" href="#vue-—-sesiones-6-a-10" aria-label="Permalink to “Vue — Sesiones 6 a 10”">​</a></h2><a class="landing-card" href="./03-vue/"><span class="landing-card__eyebrow">Bloque 3 · 5 sesiones</span><strong class="landing-card__title">Vue 3 con TypeScript</strong><span class="landing-card__description">Frontend con Vue 3 y TypeScript: componentes, reactividad, composición, arquitectura de tres capas y librería interna `@vueua/components`.</span><span class="landing-card__link">Ir al índice Vue →</span></a><h2 id="integracion-full-stack-—-sesiones-11-a-14" tabindex="-1">Integración full-stack — Sesiones 11 a 14 <a class="header-anchor" href="#integracion-full-stack-—-sesiones-11-a-14" aria-label="Permalink to “Integración full-stack — Sesiones 11 a 14”">​</a></h2><a class="landing-card" href="./04-integracion/"><span class="landing-card__eyebrow">Bloque 4 · 4 sesiones</span><strong class="landing-card__title">Integración full-stack</strong><span class="landing-card__description">Cada tema de extremo a extremo: autenticación CAS/JWT, validación, gestión de errores y DataTable conectando Oracle → .NET → Vue.</span><span class="landing-card__link">Ir al índice Integración →</span></a><h2 id="sesiones-avanzadas-—-sesiones-15-a-22" tabindex="-1">Sesiones avanzadas — Sesiones 15 a 22 <a class="header-anchor" href="#sesiones-avanzadas-—-sesiones-15-a-22" aria-label="Permalink to “Sesiones avanzadas — Sesiones 15 a 22”">​</a></h2><a class="landing-card" href="./05-avanzadas/"><span class="landing-card__eyebrow">Bloque 5 · 8 sesiones</span><strong class="landing-card__title">Avanzadas</strong><span class="landing-card__description">i18n, seguridad y menús, estado global, tests, ficheros, logs, accesibilidad y Copilot.</span><span class="landing-card__link">Ir a las avanzadas →</span></a><h2 id="proyecto-final" tabindex="-1">Proyecto final <a class="header-anchor" href="#proyecto-final" aria-label="Permalink to “Proyecto final”">​</a></h2><a class="landing-card landing-card--highlight" href="./06-proyecto-final/"><span class="landing-pill">Hilo conductor</span><strong class="landing-card__title">Aplicación de reservas en cuatro módulos progresivos</strong><span class="landing-card__description">Tipo de recurso, Recurso, Horario y Reserva: cada sesión del curso añade una pieza a tu rama. Aquí está el mapa maestro de hitos por sesión, los criterios de aceptación y la lista de control final.</span><span class="landing-card__link">Abrir el proyecto final →</span></a>',16))])}const y=s(t,[["render",p]]);export{b as __pageData,y as default};
